inbound.trace:
@{
    return JsonConvert.SerializeObject(new {
        EventName = "HealthCheckRequest",
        RequestId = context.RequestId,
        SubscriptionId = context.Subscription?.Id ?? "anonymous",
        Operation = "health",
        ClientIP = context.Request.IpAddress,
        Timestamp = DateTime.UtcNow
    });
}

return-response.set-body:
@{
                return new JObject(
                    new JProperty("status", "healthy"),
                    new JProperty("timestamp", DateTime.UtcNow.ToString("o")),
                    new JProperty("services", new JObject(
                        new JProperty("api_gateway", "healthy"),
                        new JProperty("ai_foundry", "healthy"),
                        new JProperty("key_vault", "healthy")
                    )),
                    new JProperty("version", "1.0.0")
                ).ToString();
            }

on-error.trace:
@{
    var error = context.LastError;
    return JsonConvert.SerializeObject(new {
        EventName = "HealthCheckError",
        RequestId = context.RequestId,
        ErrorSource = error?.Source,
        ErrorReason = error?.Reason,
        ErrorMessage = error?.Message,
        Timestamp = DateTime.UtcNow
    });
}
